import{_ as t,o as r,c as a,a0 as o}from"./chunks/framework.CrGeEOPE.js";const u=JSON.parse('{"title":"Acknowledgments & References","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://qbuem.com/qbuem-json/guide/acknowledgments.html"}]]},"headers":[],"relativePath":"guide/acknowledgments.md","filePath":"guide/acknowledgments.md"}'),i={name:"guide/acknowledgments.md"};function n(l,e,s,h,c,d){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="acknowledgments-references" tabindex="-1">Acknowledgments &amp; References <a class="header-anchor" href="#acknowledgments-references" aria-label="Permalink to &quot;Acknowledgments &amp; References&quot;">​</a></h1><p>qbuem-json is built on the shoulders of giants. Our performance and correctness are the result of integrating decades of research in parsing, numerical algorithms, string processing, and systems engineering.</p><p>We are committed to <strong>transparent attribution</strong> — every algorithm borrowed or adapted from an external source is documented here, in the source code, and in the relevant theory pages.</p><hr><h2 id="🔢-numeric-serialization-algorithms" tabindex="-1">🔢 Numeric Serialization Algorithms <a class="header-anchor" href="#🔢-numeric-serialization-algorithms" aria-label="Permalink to &quot;🔢 Numeric Serialization Algorithms&quot;">​</a></h2><h3 id="raffaello-giulietti-—-schubfach-algorithm" tabindex="-1">Raffaello Giulietti — Schubfach Algorithm <a class="header-anchor" href="#raffaello-giulietti-—-schubfach-algorithm" aria-label="Permalink to &quot;Raffaello Giulietti — Schubfach Algorithm&quot;">​</a></h3><ul><li><strong>What we use:</strong> The core double-to-decimal algorithm that produces the <strong>shortest round-trip decimal string</strong> for any IEEE 754 <code>double</code>. Used in <code>qj_nc::to_chars(double)</code>.</li><li><strong>Why it matters:</strong> Schubfach guarantees that parsing the output gives back the exact same <code>double</code>. No fallback path, no precision loss, no trailing-zero bloat.</li><li><strong>Source:</strong> <em>&quot;The Schubfach way to render doubles,&quot;</em> Raffaello Giulietti, 2020. <a href="https://drive.google.com/file/d/1IEeATSVnEE6TkrHlCYNY2GjaraBjOT4f" target="_blank" rel="noreferrer">PDF (Google Docs)</a></li></ul><h3 id="yyjson-—-ibireme-y-yuan-mit-license" tabindex="-1">yyjson — ibireme / Y. Yuan (MIT License) <a class="header-anchor" href="#yyjson-—-ibireme-y-yuan-mit-license" aria-label="Permalink to &quot;yyjson — ibireme / Y. Yuan (MIT License)&quot;">​</a></h3><ul><li><p><strong>What we use:</strong> Both the <strong>Schubfach port</strong> and the <strong>yy-itoa integer serialization algorithm</strong> are adapted from <a href="https://github.com/ibireme/yyjson" target="_blank" rel="noreferrer">yyjson</a>, an MIT-licensed single-file JSON library by Y. Yuan.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Adapted component</th><th style="text-align:left;">Origin in yyjson</th></tr></thead><tbody><tr><td style="text-align:left;"><code>qj_nc::to_chars(uint32/int32/uint64/int64)</code></td><td style="text-align:left;"><code>yy_write_u32</code> / <code>yy_write_u64</code> integer routines</td></tr><tr><td style="text-align:left;"><code>qj_nc::to_chars(double)</code></td><td style="text-align:left;"><code>yyjson_write_double</code> + <code>f64_bin_to_dec</code> (Schubfach)</td></tr><tr><td style="text-align:left;">128-bit pow10 table (1,336 entries)</td><td style="text-align:left;"><code>f64_pow10_sig_table</code> in <code>yyjson.c</code></td></tr><tr><td style="text-align:left;">2-digit ASCII table <code>char_table[200]</code></td><td style="text-align:left;"><code>yy_digit_table</code> in <code>yyjson.c</code></td></tr></tbody></table></li><li><p><strong>License:</strong> MIT. qbuem-json preserves this in both source comments and here.</p></li><li><p><strong>Repository:</strong> <a href="https://github.com/ibireme/yyjson" target="_blank" rel="noreferrer">https://github.com/ibireme/yyjson</a></p></li></ul><blockquote><p><strong>Why yyjson&#39;s implementation?</strong> yyjson is itself one of the fastest JSON libraries in existence. Their numeric serialization routines are carefully hand-optimized and well-tested against all IEEE 754 corner cases. Rather than writing a parallel implementation from scratch, we port and integrate their work directly, with full credit.</p></blockquote><hr><h2 id="🔬-mathematical-foundations" tabindex="-1">🔬 Mathematical Foundations <a class="header-anchor" href="#🔬-mathematical-foundations" aria-label="Permalink to &quot;🔬 Mathematical Foundations&quot;">​</a></h2><h3 id="russ-cox-google" tabindex="-1">Russ Cox (Google) <a class="header-anchor" href="#russ-cox-google" aria-label="Permalink to &quot;Russ Cox (Google)&quot;">​</a></h3><ul><li><strong>Fast Unrounded Scaling</strong>: The cornerstone of our bit-accurate <strong>number parsing</strong>. His research simplified what was historically a complex and error-prone part of systems programming. qbuem-json uses this for <code>parse()</code> stage-2 number reading.</li><li><a href="https://research.swtch.com/fp-all/" target="_blank" rel="noreferrer">Floating-Point Printing and Parsing Can Be Simple and Fast (2026)</a></li></ul><h3 id="daniel-lemire-michael-eisel" tabindex="-1">Daniel Lemire &amp; Michael Eisel <a class="header-anchor" href="#daniel-lemire-michael-eisel" aria-label="Permalink to &quot;Daniel Lemire &amp; Michael Eisel&quot;">​</a></h3><ul><li><strong>Eisel-Lemire Algorithm</strong>: For the high-speed 64-bit parsing path that handles the vast majority of well-formed JSON numbers without any bignum fallback.</li><li><a href="https://github.com/fastfloat/fast_float" target="_blank" rel="noreferrer">fast_float: 28 GB/s floating-point parsing</a></li></ul><hr><h2 id="🏎️-simd-architectural-inspiration" tabindex="-1">🏎️ SIMD &amp; Architectural Inspiration <a class="header-anchor" href="#🏎️-simd-architectural-inspiration" aria-label="Permalink to &quot;🏎️ SIMD &amp; Architectural Inspiration&quot;">​</a></h2><h3 id="simdjson-project" tabindex="-1">simdjson Project <a class="header-anchor" href="#simdjson-project" aria-label="Permalink to &quot;simdjson Project&quot;">​</a></h3><ul><li><strong>Geoff Langdale &amp; Daniel Lemire</strong>: For the groundbreaking work on <strong>two-phase SIMD parsing</strong> and structural indexing which heavily influenced our Tape DOM design. The two-stage pipeline (Stage 1: SIMD structural scan → Stage 2: scalar tape generation) is a direct extension of this architecture.</li><li><a href="https://github.com/simdjson/simdjson" target="_blank" rel="noreferrer">simdjson: Parsing gigabytes of JSON per second</a></li><li><em>Langdale &amp; Lemire, &quot;Parsing Gigabytes of JSON per Second,&quot; VLDB Journal, 2020.</em><a href="https://doi.org/10.1007/s00778-019-00578-5" target="_blank" rel="noreferrer">DOI</a></li></ul><h3 id="yyjson-tape-dom-architecture" tabindex="-1">yyjson (Tape DOM Architecture) <a class="header-anchor" href="#yyjson-tape-dom-architecture" aria-label="Permalink to &quot;yyjson (Tape DOM Architecture)&quot;">​</a></h3><p>In addition to the numeric algorithms above, yyjson independently developed a <strong>flat Tape DOM</strong> architecture (similar to simdjson&#39;s) that demonstrated the performance ceiling achievable with a contiguous node array. This validated our own DOM Tape design and provided a direct competitive reference point.</p><h3 id="glaze-—-stephen-berry-et-al" tabindex="-1">glaze — Stephen Berry et al. <a class="header-anchor" href="#glaze-—-stephen-berry-et-al" aria-label="Permalink to &quot;glaze — Stephen Berry et al.&quot;">​</a></h3><ul><li><strong>What we drew from:</strong> The <a href="https://github.com/stephenberry/glaze" target="_blank" rel="noreferrer">glaze</a> library&#39;s approach to <strong>compile-time struct registration</strong> and <strong>FNV-1a hash dispatch</strong> for field mapping informed the design of qbuem-json&#39;s Nexus Fusion engine. Specifically: <ul><li>Compile-time <code>consteval</code> FNV-1a hashing for zero-overhead field lookup</li><li>The <code>if constexpr</code> dispatch chain used in <code>append_json&lt;W, T&gt;</code> for type-generic serialization</li><li>The FastWriter concept (pre-grown buffer with raw-pointer writes) was refined in response to profiling against glaze&#39;s serialization benchmark results</li></ul></li><li><strong>License:</strong> MIT.</li><li><a href="https://github.com/stephenberry/glaze" target="_blank" rel="noreferrer">https://github.com/stephenberry/glaze</a></li></ul><blockquote><p><strong>Transparency note:</strong> qbuem-json benchmarks include glaze as a primary competitor. We believe open acknowledgment of mutual influence strengthens the ecosystem. Where qbuem-json Nexus wins, it is because we extended these ideas further. Where glaze wins (or ties), those results are published honestly in our CI benchmarks.</p></blockquote><h3 id="rapidjson" tabindex="-1">RapidJSON <a class="header-anchor" href="#rapidjson" aria-label="Permalink to &quot;RapidJSON&quot;">​</a></h3><ul><li><strong>Milo Yip</strong>: For creating the &quot;gold standard&quot; of C++ JSON libraries for a decade and providing the modular Handler-based design inspiration.</li><li><a href="https://rapidjson.org/" target="_blank" rel="noreferrer">RapidJSON Documentation</a></li></ul><hr><h2 id="🛠️-infrastructure-tools" tabindex="-1">🛠️ Infrastructure &amp; Tools <a class="header-anchor" href="#🛠️-infrastructure-tools" aria-label="Permalink to &quot;🛠️ Infrastructure &amp; Tools&quot;">​</a></h2><ul><li><strong>VitePress</strong>: For the beautiful documentation framework.</li><li><strong>Google Benchmark (Google Test + Google Mock)</strong>: For the test infrastructure that validates every claim.</li><li><strong>GitHub Actions</strong>: For CI across three native hardware runners (x86_64, aarch64, Apple Silicon).</li></ul><hr><h2 id="📝-full-reference-list" tabindex="-1">📝 Full Reference List <a class="header-anchor" href="#📝-full-reference-list" aria-label="Permalink to &quot;📝 Full Reference List&quot;">​</a></h2><ol><li><p><strong>Raffaello Giulietti</strong>, <em>&quot;The Schubfach way to render doubles,&quot;</em> 2020. <a href="https://drive.google.com/file/d/1IEeATSVnEE6TkrHlCYNY2GjaraBjOT4f" target="_blank" rel="noreferrer">PDF</a></p></li><li><p><strong>Y. Yuan (ibireme)</strong>, <em>yyjson — A fast JSON library in ANSI C,</em> 2020–present. <a href="https://github.com/ibireme/yyjson" target="_blank" rel="noreferrer">GitHub (MIT)</a></p></li><li><p><strong>Russ Cox</strong>, <em>&quot;Floating-Point Printing and Parsing Can Be Simple and Fast,&quot;</em> 2026. <a href="https://research.swtch.com/fp-all/" target="_blank" rel="noreferrer">Blog</a></p></li><li><p><strong>Daniel Lemire</strong>, <em>&quot;Number Parsing at Gigabytes per Second,&quot;</em> SPE, 2021. <a href="https://arxiv.org/abs/2101.11408" target="_blank" rel="noreferrer">arXiv</a></p></li><li><p><strong>Michael Eisel &amp; Daniel Lemire</strong>, <em>&quot;The Eisel-Lemire Algorithm,&quot;</em> 2020. <a href="https://github.com/fastfloat/fast_float" target="_blank" rel="noreferrer">fast_float</a></p></li><li><p><strong>Langdale &amp; Lemire</strong>, <em>&quot;Parsing Gigabytes of JSON per Second,&quot;</em> VLDB Journal, 2020. <a href="https://doi.org/10.1007/s00778-019-00578-5" target="_blank" rel="noreferrer">DOI</a></p></li><li><p><strong>Stephen Berry et al.</strong>, <em>glaze — Extremely fast, in-memory, JSON and interface library,</em> 2022–present. <a href="https://github.com/stephenberry/glaze" target="_blank" rel="noreferrer">GitHub (MIT)</a></p></li></ol><hr><div class="tip custom-block"><p class="custom-block-title">❤️ To the C++ Community</p><p>To the C++ community: thank you for pushing the boundaries of what is possible with modern C++. Every open-source library listed here made qbuem-json possible. We hope to contribute back in kind.</p></div>',35)])])}const m=t(i,[["render",n]]);export{u as __pageData,m as default};
